import type { Metadata } from "next";
import RailPointsView from "./RailPointsView";

export const metadata: Metadata = {
  title: "マイIC・ポイント | モバイルSuica",
  description: "IC残高・JRE POINT・会員ステージ・利用履歴をまとめて確認できる会員画面。",
};

// Server Component shell. All interactivity + function props (ListCard onSelect,
// useState, formatters passed through JSX) live inside the "use client"
// RailPointsView so `next build` stays happy.
export default function RailPointsPage() {
  return (
    <div className="min-h-screen bg-muted/30">
      <RailPointsView />
    </div>
  );
}

// Domain data for the モバイルIC + ポイント（会員）画面.
// Pure data — no JSX, no function props — so it stays RSC-safe and can be
// imported by either a Server or Client Component.

export type MemberStage = "ブロンズ" | "シルバー" | "ゴールド" | "プラチナ";

export interface MemberSummary {
  name: string;
  /** モバイルSuica の SF残高（IC残高）円 */
  icBalance: number;
  /** JRE POINT 残高 */
  points: number;
  /** 会員ステージ */
  stage: MemberStage;
  /** 次のステージまでに必要な、当年の獲得ポイント */
  stageTarget: number;
  /** 当年これまでの獲得ポイント（ステージ判定用） */
  stageEarned: number;
  /** 今月末に失効予定のポイント */
  expiringPoints: number;
  expiringDate: string;
}

export interface AutoCharge {
  enabled: boolean;
  /** 残高がこの額以下になったら */
  thresholdYen: number;
  /** この額をチャージ */
  amountYen: number;
}

export type IcTxnKind = "乗車" | "物販" | "入金";

export interface IcTxn {
  id: string;
  kind: IcTxnKind;
  /** 乗車なら "新宿駅 → 東京駅"、物販なら店名、入金なら "オートチャージ" など */
  title: string;
  /** 補足（路線名・支払手段・時刻など） */
  detail: string;
  datetime: string;
  /** 増減額（円）。乗車・物販はマイナス、入金はプラス。 */
  amountYen: number;
  /** この取引で獲得したJRE POINT（なければ0） */
  earnedPoints?: number;
}

export type PointKind = "獲得" | "利用" | "失効予定";

export interface PointTxn {
  id: string;
  kind: PointKind;
  title: string;
  detail: string;
  datetime: string;
  /** 増減ポイント。獲得はプラス、利用・失効はマイナス。 */
  points: number;
}

export interface Commuter {
  /** 区間 */
  section: string;
  /** 種類（通勤 / 通学 / 1ヶ月 / 3ヶ月 など） */
  kind: string;
  /** 経由 */
  via: string;
  validFrom: string;
  validTo: string;
  /** 更新まで残り日数 */
  daysLeft: number;
}

export interface Campaign {
  id: string;
  title: string;
  body: string;
  badge: string;
  deadline: string;
}

export const member: MemberSummary = {
  name: "佐藤 美咲",
  icBalance: 3284,
  points: 1820,
  stage: "シルバー",
  stageTarget: 3000,
  stageEarned: 2150,
  expiringPoints: 340,
  expiringDate: "2026/06/30",
};

export const autoCharge: AutoCharge = {
  enabled: true,
  thresholdYen: 1000,
  amountYen: 3000,
};

export const icTxns: IcTxn[] = [
  {
    id: "ic1",
    kind: "乗車",
    title: "新宿駅 → 東京駅",
    detail: "JR中央線（快速）",
    datetime: "6/27 08:42",
    amountYen: -210,
    earnedPoints: 2,
  },
  {
    id: "ic2",
    kind: "物販",
    title: "NewDays 東京中央口店",
    detail: "モバイルSuica 決済",
    datetime: "6/27 08:55",
    amountYen: -298,
    earnedPoints: 3,
  },
  {
    id: "ic3",
    kind: "乗車",
    title: "東京駅 → 品川駅",
    detail: "JR山手線",
    datetime: "6/26 19:08",
    amountYen: -170,
    earnedPoints: 1,
  },
  {
    id: "ic4",
    kind: "物販",
    title: "エキュート品川 ベーカリー",
    detail: "モバイルSuica 決済",
    datetime: "6/26 19:20",
    amountYen: -540,
    earnedPoints: 5,
  },
  {
    id: "ic5",
    kind: "入金",
    title: "オートチャージ",
    detail: "ビューカード",
    datetime: "6/26 19:08",
    amountYen: 3000,
  },
  {
    id: "ic6",
    kind: "物販",
    title: "自販機 acure（品川駅5番ホーム）",
    detail: "モバイルSuica 決済",
    datetime: "6/25 18:31",
    amountYen: -160,
    earnedPoints: 1,
  },
];

export const pointTxns: PointTxn[] = [
  {
    id: "p1",
    kind: "獲得",
    title: "乗車ポイント",
    detail: "リピートポイント・運賃の一部還元",
    datetime: "6/27",
    points: 6,
  },
  {
    id: "p2",
    kind: "獲得",
    title: "物販ポイント NewDays",
    detail: "200円ごとに +1〜",
    datetime: "6/27",
    points: 8,
  },
  {
    id: "p3",
    kind: "利用",
    title: "Suicaチャージへ交換",
    detail: "1ポイント = 1円",
    datetime: "6/24",
    points: -500,
  },
  {
    id: "p4",
    kind: "失効予定",
    title: "有効期限切れ予定",
    detail: "2026/06/30 まで",
    datetime: "6/30",
    points: -340,
  },
];

export const commuter: Commuter = {
  section: "中野駅 〜 東京駅",
  kind: "通勤 1ヶ月",
  via: "JR中央線（快速）経由",
  validFrom: "2026/06/05",
  validTo: "2026/07/04",
  daysLeft: 7,
};

export const campaigns: Campaign[] = [
  {
    id: "c1",
    title: "駅ナカ NewDays でポイント3倍",
    body: "対象店舗のモバイルSuica決済で6月末まで還元率アップ。",
    badge: "期間限定",
    deadline: "〜6/30",
  },
  {
    id: "c2",
    title: "Suicaチャージへの交換で +5%",
    body: "1,000ポイント以上のチャージ交換で増量。今月キャンペーン。",
    badge: "増量中",
    deadline: "〜6/30",
  },
];

export const STAGE_NEXT: Record<MemberStage, MemberStage | null> = {
  ブロンズ: "シルバー",
  シルバー: "ゴールド",
  ゴールド: "プラチナ",
  プラチナ: null,
};

"use client";

import * as React from "react";
import {
  Badge,
  Banner,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  ListCard,
  MetadataList,
  Progress,
  Separator,
  Statistic,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  formatCurrency,
  formatNumber,
} from "@gunjo/ui";
import {
  IconArrowsExchange,
  IconBolt,
  IconBuildingStore,
  IconChevronRight,
  IconCoin,
  IconGift,
  IconPlus,
  IconReceipt,
  IconSettings,
  IconTicket,
  IconTrain,
  IconWallet,
} from "@tabler/icons-react";

import {
  autoCharge,
  campaigns,
  commuter,
  icTxns,
  member,
  pointTxns,
  STAGE_NEXT,
  type IcTxn,
  type MemberStage,
  type PointTxn,
} from "./data";

/* ------------------------------------------------------------------ */
/* Small presentational helpers                                        */
/* ------------------------------------------------------------------ */

const STAGE_BADGE: Record<MemberStage, string> = {
  ブロンズ: "bg-[hsl(25_45%_45%)] text-white",
  シルバー: "bg-[hsl(220_8%_70%)] text-[hsl(220_20%_20%)]",
  ゴールド: "bg-[hsl(42_70%_55%)] text-[hsl(40_60%_15%)]",
  プラチナ: "bg-[hsl(210_15%_85%)] text-[hsl(210_25%_25%)]",
};

function yen(n: number): string {
  return formatCurrency(n, { signed: n < 0 });
}

function points(n: number): string {
  return `${formatNumber(n, { signed: true })}P`;
}

/** A section title with a "もっと見る" trailing link — repeated 4×, so factored out. */
function SectionHeader({
  icon,
  title,
  actionLabel,
}: {
  icon: React.ReactNode;
  title: string;
  actionLabel?: string;
}) {
  return (
    <div className="flex items-center justify-between px-1">
      <h2 className="flex items-center gap-2 text-base font-semibold text-foreground">
        <span className="text-muted-foreground" aria-hidden>
          {icon}
        </span>
        {title}
      </h2>
      {actionLabel ? (
        <Button variant="link" size="sm" className="h-auto px-0 text-muted-foreground">
          {actionLabel}
          <IconChevronRight className="size-4" aria-hidden />
        </Button>
      ) : null}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* IC transaction row                                                  */
/* ------------------------------------------------------------------ */

const IC_ICON: Record<IcTxn["kind"], React.ReactNode> = {
  乗車: <IconTrain className="size-5" aria-hidden />,
  物販: <IconBuildingStore className="size-5" aria-hidden />,
  入金: <IconPlus className="size-5" aria-hidden />,
};

function IcRow({ txn, onSelect }: { txn: IcTxn; onSelect: (t: IcTxn) => void }) {
  const positive = txn.amountYen > 0;
  return (
    <ListCard
      onSelect={() => onSelect(txn)}
      leading={
        <span
          className="flex size-9 items-center justify-center rounded-full bg-muted text-muted-foreground"
          aria-hidden
        >
          {IC_ICON[txn.kind]}
        </span>
      }
      title={txn.title}
      description={
        <>
          {txn.detail}
          {txn.earnedPoints ? (
            <span className="ml-1.5 text-success-strong">+{txn.earnedPoints}P</span>
          ) : null}
        </>
      }
      meta={txn.datetime}
      status={
        <span
          className={
            "text-sm font-semibold tabular-nums " +
            (positive ? "text-success-strong" : "text-foreground")
          }
        >
          {yen(txn.amountYen)}
        </span>
      }
    />
  );
}

/* ------------------------------------------------------------------ */
/* Point transaction row                                               */
/* ------------------------------------------------------------------ */

const POINT_META: Record<
  PointTxn["kind"],
  { icon: React.ReactNode; badge: React.ComponentProps<typeof Badge>["variant"]; tone: string }
> = {
  獲得: { icon: <IconCoin className="size-4" aria-hidden />, badge: "success", tone: "text-success-strong" },
  利用: { icon: <IconArrowsExchange className="size-4" aria-hidden />, badge: "info", tone: "text-foreground" },
  失効予定: { icon: <IconBolt className="size-4" aria-hidden />, badge: "warning", tone: "text-warning-strong" },
};

function PointRow({ txn }: { txn: PointTxn }) {
  const m = POINT_META[txn.kind];
  return (
    <ListCard
      leading={
        <span
          className="flex size-9 items-center justify-center rounded-full bg-muted text-muted-foreground"
          aria-hidden
        >
          {m.icon}
        </span>
      }
      title={txn.title}
      description={txn.detail}
      tags={<Badge variant={m.badge}>{txn.kind}</Badge>}
      meta={txn.datetime}
      status={<span className={"text-sm font-semibold tabular-nums " + m.tone}>{points(txn.points)}</span>}
    />
  );
}

/* ------------------------------------------------------------------ */
/* Main view                                                           */
/* ------------------------------------------------------------------ */

export default function RailPointsView() {
  const [selected, setSelected] = React.useState<IcTxn | null>(null);
  const nextStage = STAGE_NEXT[member.stage];
  const stagePct = Math.min(100, Math.round((member.stageEarned / member.stageTarget) * 100));
  const remain = Math.max(0, member.stageTarget - member.stageEarned);

  return (
    <main className="mx-auto w-full max-w-md px-4 pb-24 pt-4">
      {/* App-level header */}
      <header className="mb-4 flex items-center justify-between">
        <div>
          <p className="text-xs text-muted-foreground">モバイルSuica・JRE POINT</p>
          <h1 className="text-lg font-bold text-foreground">マイIC・ポイント</h1>
        </div>
        <Button variant="ghost" size="icon" aria-label="設定">
          <IconSettings className="size-5" aria-hidden />
        </Button>
      </header>

      {/* ---------------------------------------------------------------- */}
      {/* HERO — 残高 / ポイント / ステージ                                   */}
      {/* HAND-ROLLED: no loyalty/balance summary component exists.          */}
      {/* ---------------------------------------------------------------- */}
      <section
        aria-labelledby="hero-heading"
        className="relative overflow-hidden rounded-2xl bg-[hsl(var(--gunjo-deeper))] p-5 text-white shadow-sm"
        style={{
          backgroundImage:
            "radial-gradient(120% 120% at 100% 0%, hsl(var(--gunjo-mid) / 0.55) 0%, transparent 55%)",
        }}
      >
        <h2 id="hero-heading" className="sr-only">
          残高とポイントの概要
        </h2>

        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <IconWallet className="size-5 text-white/80" aria-hidden />
            <span className="text-sm text-white/80">IC残高（SF）</span>
          </div>
          <span
            className={
              "rounded-full px-2.5 py-1 text-xs font-bold " + STAGE_BADGE[member.stage]
            }
          >
            {member.stage}会員
          </span>
        </div>

        <p className="mt-1 text-4xl font-bold tabular-nums tracking-tight">
          {formatCurrency(member.icBalance)}
        </p>

        <div className="mt-4 flex items-end justify-between">
          <div>
            <p className="text-xs text-white/70">JRE POINT 残高</p>
            <p className="text-2xl font-bold tabular-nums">
              {formatNumber(member.points)}
              <span className="ml-1 text-base font-medium">P</span>
            </p>
          </div>
          <Button
            variant="secondary"
            size="sm"
            className="bg-white/15 text-white hover:bg-white/25"
          >
            <IconArrowsExchange className="size-4" aria-hidden />
            ポイント交換
          </Button>
        </div>

        {/* Stage progress */}
        {nextStage ? (
          <div className="mt-4">
            <div className="mb-1.5 flex items-center justify-between text-xs text-white/80">
              <span>
                {nextStage}まであと{" "}
                <span className="font-semibold text-white">{formatNumber(remain)}P</span>
              </span>
              <span className="tabular-nums">
                {formatNumber(member.stageEarned)} / {formatNumber(member.stageTarget)}P
              </span>
            </div>
            <Progress
              value={member.stageEarned}
              max={member.stageTarget}
              tone="warning"
              label={`${nextStage}までの進捗`}
              valueText={`${stagePct}% 達成`}
              className="h-2 bg-white/20"
            />
          </div>
        ) : null}
      </section>

      {/* Expiry warning — Banner */}
      {member.expiringPoints > 0 ? (
        <Banner
          variant="warning"
          className="mt-3 h-auto rounded-lg py-2"
          icon={<IconBolt className="size-4" aria-hidden />}
          action={
            <Button variant="warning" size="xs">
              今すぐ使う
            </Button>
          }
        >
          {formatNumber(member.expiringPoints)}P が {member.expiringDate} に失効します
        </Banner>
      ) : null}

      {/* ---------------------------------------------------------------- */}
      {/* チャージ / オートチャージ                                          */}
      {/* ---------------------------------------------------------------- */}
      <section aria-labelledby="charge-heading" className="mt-6 space-y-2">
        <h2 id="charge-heading" className="px-1 text-base font-semibold text-foreground">
          チャージ
        </h2>
        <div className="grid grid-cols-2 gap-2">
          <Button variant="primary" size="lg" className="h-12 w-full">
            <IconPlus className="size-5" aria-hidden />
            チャージする
          </Button>
          <Button variant="outline" size="lg" className="h-12 w-full">
            <IconReceipt className="size-5" aria-hidden />
            きっぷを買う
          </Button>
        </div>

        <Card className="flex-row items-center justify-between gap-3 p-3">
          <div className="flex min-w-0 items-center gap-3">
            <span className="flex size-9 shrink-0 items-center justify-center rounded-full bg-primary-subtle text-primary-strong">
              <IconBolt className="size-5" aria-hidden />
            </span>
            <div className="min-w-0">
              <p className="flex items-center gap-2 text-sm font-medium text-foreground">
                オートチャージ
                <Badge variant={autoCharge.enabled ? "success" : "outline"}>
                  {autoCharge.enabled ? "ON" : "OFF"}
                </Badge>
              </p>
              <p className="truncate text-xs text-muted-foreground">
                残高{formatCurrency(autoCharge.thresholdYen)}以下で{" "}
                {formatCurrency(autoCharge.amountYen)}チャージ
              </p>
            </div>
          </div>
          <Button variant="ghost" size="sm" className="shrink-0">
            変更
          </Button>
        </Card>
      </section>

      {/* ---------------------------------------------------------------- */}
      {/* 定期券                                                            */}
      {/* ---------------------------------------------------------------- */}
      <section aria-labelledby="commuter-heading" className="mt-6 space-y-2">
        <SectionHeader
          icon={<IconTicket className="size-5" />}
          title="定期券"
        />
        <Card className="p-4">
          <div className="flex items-start justify-between gap-3">
            <div className="min-w-0">
              <p className="text-base font-semibold text-foreground">{commuter.section}</p>
              <p className="mt-0.5 text-xs text-muted-foreground">{commuter.via}</p>
            </div>
            <Badge variant={commuter.daysLeft <= 7 ? "warning" : "secondary"}>
              {commuter.kind}
            </Badge>
          </div>
          <Separator className="my-3" />
          <MetadataList
            variant="compact"
            items={[
              { label: "有効期限", value: `${commuter.validFrom} 〜 ${commuter.validTo}` },
              {
                label: "更新",
                value: (
                  <span className="text-warning-strong">残り {commuter.daysLeft} 日</span>
                ),
              },
            ]}
          />
          <Button variant="outline" size="sm" className="mt-3 w-full">
            定期券を更新する
          </Button>
        </Card>
      </section>

      {/* ---------------------------------------------------------------- */}
      {/* 履歴 — IC / ポイント tabs                                          */}
      {/* ---------------------------------------------------------------- */}
      <section aria-labelledby="history-heading" className="mt-6">
        <h2 id="history-heading" className="mb-2 px-1 text-base font-semibold text-foreground">
          利用履歴
        </h2>
        <Tabs defaultValue="ic" className="border-0">
          <TabsList className="w-full">
            <TabsTrigger value="ic" className="flex-1">
              IC利用
            </TabsTrigger>
            <TabsTrigger value="points" className="flex-1">
              ポイント
            </TabsTrigger>
          </TabsList>

          <TabsContent value="ic" className="mt-3 space-y-2 p-0">
            {icTxns.map((t) => (
              <IcRow key={t.id} txn={t} onSelect={setSelected} />
            ))}
          </TabsContent>

          <TabsContent value="points" className="mt-3 space-y-2 p-0">
            {pointTxns.map((t) => (
              <PointRow key={t.id} txn={t} />
            ))}
          </TabsContent>
        </Tabs>
      </section>

      {/* Selected IC txn detail — lightweight inline detail, no Dialog dependency */}
      {selected ? (
        <Card
          role="status"
          className="mt-3 border-primary-border bg-primary-subtle p-3"
        >
          <p className="text-xs text-primary-subtle-foreground">選択中の取引</p>
          <div className="mt-1 flex items-center justify-between">
            <span className="font-medium text-foreground">{selected.title}</span>
            <Button variant="ghost" size="xs" onClick={() => setSelected(null)}>
              閉じる
            </Button>
          </div>
          <Statistic
            className="mt-2 border-0 bg-transparent p-0"
            label={`${selected.kind}・${selected.datetime}`}
            value={yen(selected.amountYen)}
          />
        </Card>
      ) : null}

      {/* ---------------------------------------------------------------- */}
      {/* キャンペーン                                                       */}
      {/* ---------------------------------------------------------------- */}
      <section aria-labelledby="campaign-heading" className="mt-6 space-y-2">
        <SectionHeader
          icon={<IconGift className="size-5" />}
          title="おすすめ・キャンペーン"
          actionLabel="もっと見る"
        />
        {campaigns.map((c) => (
          <ListCard
            key={c.id}
            onSelect={() => undefined}
            severity="info"
            leading={
              <span className="flex size-9 items-center justify-center rounded-full bg-info-subtle text-info">
                <IconGift className="size-5" aria-hidden />
              </span>
            }
            title={c.title}
            description={c.body}
            tags={<Badge variant="info">{c.badge}</Badge>}
            meta={c.deadline}
          />
        ))}
      </section>
    </main>
  );
}
